import{l as i,o as r,h as s,w as l,m as d,b as e,d as t}from"./app.543f262f.js";const h=e("div",{class:"markdown-body"},[e("h2",null,"Trading Bot Journey"),e("p",null,[t("This is a writeup of the machine-learning project I spent most of the last year on: an attempt to forecast short-horizon outcomes from limit-order-book data on BTC/USDT perpetual futures, using a Transformer encoder feeding a Mixture-of-Experts head. Repo here: "),e("a",{href:"https://github.com/SlaytonNichols/hyro-trader-ml-project"},"hyro-trader-ml-project"),t(".")]),e("p",null,[t("The trading P&L on this project was mixed. The system and the methodology I came out the other side of it with are the durable artifacts, and that\u2019s what this post is about. A companion post, "),e("a",{href:"/posts/trading-bot-journey-part-2"},"A Working Toolkit for Ambiguous, Data-Heavy Problems"),t(", pulls the methodology pieces out of the trading context.")]),e("hr"),e("h3",null,"The thesis"),e("p",null,[t("The goal was to pass a $200K prop-firm challenge. The original approach was to forecast "),e("strong",null,"microstructure response patterns"),t(" at the limit-order-book (L2) level \u2014 absorption, liquidity vacuums, exhaustion \u2014 instead of trying to predict price direction directly. Edges of a few basis points per trade, maker-only execution, high frequency.")]),e("p",null,[t("I started with handcrafted L2 signals on QuantConnect LEAN, built a 24/7 Bybit WebSocket recorder that eventually accumulated 363M+ orderbook rows, and validated five signal hypotheses on rolling walk-forwards. Three of the five looked promising. The limitation was that I was encoding "),e("em",null,"my own assumptions"),t(" about which patterns mattered, rather than letting the data identify them. That pushed me toward neural networks.")]),e("hr"),e("h3",null,"Train on outcomes, not on patterns"),e("p",null,"The reframing was: instead of labeling a row \u201Cthis is an absorption pattern,\u201D label it with what actually happened next \u2014 did price move favorably, by how much, did you get adversely selected, did the order even fill? Then let the model learn which input patterns lead to which outcomes."),e("p",null,[t("The architecture I ran live (V3.7) is in "),e("code",null,"models/"),t(" and "),e("code",null,"training/"),t(" in the repo:")]),e("ul",null,[e("li",null,"4-layer Transformer encoder, ~850K parameters"),e("li",null,"8-expert Mixture-of-Experts head with a learned gating network"),e("li",null,[t("89 input features across L2 depth, queue dynamics, temporal, and seasonality groups ("),e("code",null,"features/"),t(")")]),e("li",null,[t("7 output heads \u2014 entry probability, direction, expected edge in bps, MFE, MAE, adverse-selection probability, fill probability ("),e("code",null,"labels/"),t(")")]),e("li",null,"Trained on Databricks with V100 GPUs over ~1.5M samples at 100ms resolution")]),e("p",null,[t("It went live on January 31, 2026. Across 437 trades over six days it ran a 40.5% win rate with positive overall P&L. The most useful observation from those six days had nothing to do with the architecture: "),e("strong",null,"fast fills were a warning sign."),t(" Orders filled in under 5 seconds averaged negative P&L; slower fills, where I was actually providing liquidity, were profitable. Fast fills usually meant somebody was running through my level \u2014 adverse selection. That observation reframed the whole problem from \u201Cwhich way is price going\u201D to \u201Ccan I get filled in a place where I\u2019m providing genuine liquidity instead of getting picked off.\u201D")]),e("hr"),e("h3",null,"Then I noticed the data was wrong"),e("p",null,"While the model was live, I went back and audited the training pipeline. I found three simultaneous bugs:"),e("ul",null,[e("li",null,"Bid and ask were inverted on snapshots."),e("li",null,[t("Spreads were inflated 32\u2013118\xD7 because the pipeline was treating delta messages as full orderbook snapshots instead of statefully reconstructing the book ("),e("code",null,"data/book_parser.py"),t(" is the corrected version).")]),e("li",null,"Book depth indexing was returning the wrong levels.")]),e("p",null,"The model was scoring well on validation despite all of this, because the validation data was corrupted in the same way. A model that fails obviously is easy to catch. One that looks good on flawed data ships."),e("p",null,"I stopped iterating on architecture and committed to three constraints I\u2019d been working without:"),e("ol",null,[e("li",null,[e("strong",null,"No Databricks in the runtime path."),t(" Research can use it; live execution cannot depend on it.")]),e("li",null,[e("strong",null,"One feature code path."),t(" The function that produces a feature in training is the function imported by the live runner. Same code, not a \u201Cported\u201D version.")]),e("li",null,[e("strong",null,"Versioned model artifacts."),t(" Every checkpoint gets a SemVer tag, with normalization stats, feature list, training config, and git SHA bundled in (see "),e("code",null,"docs/VERSIONING.md"),t(").")])]),e("p",null,"Then I rebuilt the pipeline correctly, regenerated features and labels on clean data, retrained, and asked one question: with the data fixed, does the model work?"),e("hr"),e("h3",null,"Three diagnostic tests that ruled out the strategy class"),e("p",null,"Rather than tweak the model and hope, I designed three orthogonal experiments. The point was: if all three say the same thing, the strategy class itself is the constraint, not the implementation."),e("p",null,[e("strong",null,"Leg A \u2014 oracle direction test."),t(" Take the model\u2019s actual predictions but assume perfect direction picking. At the deployed entry threshold, the result was \u22120.82 bps per trade. Sweeping the threshold up, I could find a setting that returned +2.94 to +6.44 bps per trade \u2014 but the trade count collapsed from ~9/day to ~1/day. There was a profitable signal in the data, just not enough qualifying setups to deploy capital against.")]),e("p",null,[e("strong",null,"Leg B \u2014 cheaper alternatives."),t(" I tested whether the dual direction/edge heads were fighting each other (a unified signed-edge regression head) and whether the 73-feature set was too noisy (a stripped-down 15-feature order-flow-only model). Both performed worse than the baseline.")]),e("p",null,[e("strong",null,"Leg C \u2014 substrate audit."),t(" Before declaring L2 dead, I tested whether "),e("em",null,"any"),t(" feature combination at "),e("em",null,"any"),t(" horizon could clear the 4 bps maker-maker fee floor. Best L2 feature at best horizon: +0.44 bps. Adding tape-derived features: +0.06 bps. Resampling to 1-minute bars and testing 5/15/60-minute horizons: nothing crossed. One expanded feature set hit +2.32 bps on a single test split, then collapsed to a +0.93 bps median across five independent walk-forward folds, with two folds going negative \u2014 period-specific luck, not durable edge.")]),e("p",null,[t("The full writeups are in "),e("code",null,"docs/"),t(" ("),e("code",null,"LEG_A_*"),t(", "),e("code",null,"LEG_B_*"),t(", "),e("code",null,"LEG_C_*"),t(", "),e("code",null,"SUBSTRATE_VERDICT_*"),t(").")]),e("p",null,"Three orthogonal tests, same conclusion. At retail latency and retail fees, the L2 substrate doesn\u2019t carry enough signal to support a price-prediction strategy. That conclusion was worth more than another quarter of architecture iteration."),e("hr"),e("h3",null,"A brief detour: trading relationships instead of direction"),e("p",null,[t("Once the L2 direction approach was off the table, the natural next question was whether some "),e("em",null,"pair"),t(" of prices has a more predictable relative move than either\u2019s absolute move. Two cointegrated perps drift around a stable spread; when the spread dislocates, you can trade the dislocation without taking a directional view on either leg.")]),e("p",null,"I built and deployed a spread-momentum system across 30 cointegrated perp pairs (z-score entries on the rolling log-spread, momentum exits). It ran on Azure Container Instances under $20/month with no GPU dependency \u2014 a cleaner deployment than V3.7 in every respect. The signal was real; under honest cost assumptions it wasn\u2019t strong enough to justify the prop-firm challenge cost against it. So I parked it."),e("p",null,"That work lives in a separate repo. The point for this post is that the diagnostic discipline from the L2 work \u2014 feasibility math first, walk-forward folds over single splits, design experiments that could prove you wrong \u2014 transferred directly and saved months."),e("hr"),e("h3",null,"What I came away with"),e("p",null,"This was my first end-to-end ML system, and a lot of what I\u2019d carry into the next one is engineering and methodology rather than architecture. Some of these will read as obvious \u2014 they\u2019re on the list because they were genuine lessons the first time through, and now they\u2019re things I\u2019d build in from the start."),e("ol",null,[e("li",null,[e("p",null,[e("strong",null,"One feature code path across training and live."),t(" Computing the same feature in three places \u2014 Spark notebook, local backtest, live runner \u2014 guarantees they will diverge. Pin one implementation, import it everywhere.")])]),e("li",null,[e("p",null,[e("strong",null,"Training/serving parity tests on every deploy."),t(" Push the same raw input through the training feature path and the live feature path; assert the resulting tensors are equal. This catches an entire class of \u201Cthe model worked yesterday and is broken today\u201D before it happens.")])]),e("li",null,[e("p",null,[e("strong",null,"Cheap data-sanity checks before any model sees the data."),t(" Things like \u201Cask price should be greater than bid price\u201D or \u201Cspread shouldn\u2019t be 100x normal\u201D are one-line assertions. If you put them at the point where data enters the pipeline, the bad data fails loudly instead of silently corrupting training. The three bugs from this project would have all been caught by checks of this kind.")])]),e("li",null,[e("p",null,[e("strong",null,"Versioned, immutable model artifacts."),t(" SemVer the checkpoint. Bundle normalization stats, feature list, training config, and git SHA into the artifact itself.")])]),e("li",null,[e("p",null,[e("strong",null,"Test on multiple time periods, not just one."),t(" If you only evaluate a model on one slice of data, a good result might just be luck \u2014 that particular slice happened to suit the model. The fix is to repeat the evaluation across several different time windows and look at the "),e("em",null,"spread"),t(" of results. In this project, an experiment looked great on one slice (+2.32 bps) and almost broke even when re-tested across five slices (+0.93 bps median, two of them losing money). The single-slice number was the lie. Catching that before deploying capital is much cheaper than catching it after.")])]),e("li",null,[e("p",null,[e("strong",null,"Live as the honest evaluator."),t(" Backtests and validation metrics exist to give you confidence to "),e("em",null,"go"),t(" live, not to certify that the system works. Adverse selection, fill latency, requote dynamics, exchange quirks \u2014 these only show up under real conditions.")])]),e("li",null,[e("p",null,[e("strong",null,"Feasibility math at the start, not after the model."),t(" Expected edge minus fees minus adverse selection minus slippage. If that isn\u2019t positive with margin, no amount of model tuning fixes it. The L2 work had a real signal but ~4 bps of best-case fees against a similar-magnitude per-trigger payoff. A 20-minute calculation up front sets the right expectations.")])])]),e("p",null,[t("The transferable version of these \u2014 pulled out of the trading context \u2014 is in "),e("a",{href:"/posts/trading-bot-journey-part-2"},"A Working Toolkit for Ambiguous, Data-Heavy Problems"),t(".")])],-1),f="Trading Bot Journey",y="A year building a Transformer + Mixture-of-Experts model for crypto microstructure trading on Bybit. The architecture, the training pipeline, the diagnostic experiments that ruled out the strategy class, and what I came away with.",w="2026-04-29T00:00:00.000Z",b=["ml","trading","data-engineering","python"],v=!1,T=!0,k=[{property:"og:title",content:"Trading Bot Journey"}],x={__name:"trading-bot-journey",setup(u,{expose:a}){const n={title:"Trading Bot Journey",summary:"A year building a Transformer + Mixture-of-Experts model for crypto microstructure trading on Bybit. The architecture, the training pipeline, the diagnostic experiments that ruled out the strategy class, and what I came away with.",date:"2026-04-29T00:00:00.000Z",tags:["ml","trading","data-engineering","python"],draft:!1,pinned:!0,meta:[{property:"og:title",content:"Trading Bot Journey"}]};return a({frontmatter:n}),i({title:"Trading Bot Journey",meta:[{property:"og:title",content:"Trading Bot Journey"}]}),(p,g)=>{const o=d;return r(),s(o,{frontmatter:n},{default:l(()=>[h]),_:1})}}};export{w as date,x as default,v as draft,k as meta,T as pinned,y as summary,b as tags,f as title};
